			&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;font-weight: 700;&quot;&gt;संस्कृत&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;89 (नवासी)&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;नवाशीति&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;89&amp;nbsp;(नवासी)&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;&quot;&gt;नवाशीति&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;96 (छियानवे)&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;षण्णवति&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;99 (निन्यानवे)&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;p style=&quot;text-align: center;&quot;&gt;&lt;span style=&quot;&quot;&gt;नवनवति&lt;/span&gt;&lt;/p&gt;
			&lt;/td&gt;
		&lt;/tr&gt;
