&lt;p&gt;&lt;span style=&quot;&quot;&gt;&lt;strong&gt;अन्य विकल्प&lt;/strong&gt; -&lt;/span&gt;&lt;/p&gt;

&lt;ul&gt;
	&lt;li&gt;&lt;strong&gt;कामार्त्ता हि प्रकृतिकृपणाश्चेतनाचेतनेषु&lt;/strong&gt;&amp;nbsp;- यह पंक्ति &lt;strong&gt;मेघदूत&lt;/strong&gt; में उद्धृत है।&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;याञ्चा मोघा वरमधिगुणे नाधमे लब्धकामाः&lt;/strong&gt; -&amp;nbsp;&lt;span style=&quot;&quot;&gt;यह पंक्ति&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;मेघदूत&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;में उद्धृत है।&lt;/span&gt;&lt;/li&gt;
	&lt;li&gt;&lt;strong&gt;तरलहृदयमप्रतिबुद्धञ्च मदयन्ति धनानि&lt;/strong&gt;&amp;nbsp;- यह पंक्ति &lt;strong&gt;कादम्बरी-शुकनासोपदेश&lt;/strong&gt; में उद्धृत है।&lt;/li&gt;
&lt;/ul&gt;
